var FastMCPEventEmitterBase = EventEmitter;
var FastMCPEventEmitter = class extends FastMCPEventEmitterBase {
};
var FastMCP = class extends FastMCPEventEmitter {
  constructor(options) {
    super();
    this.options = options;
    this.#options = options;
    this.#authenticate = options.authenticate;
  }
  #options;
  #prompts = [];
  #resources = [];
  #resourcesTemplates = [];
  #sessions = [];
  #sseServer = null;
  #tools = [];
  #authenticate;
  get sessions() {
    return this.#sessions;
  }
  addTool(tool) {
    this.#tools.push(tool);
  }
  addResource(resource) {
    this.#resources.push(resource);
  }
  addResourceTemplate(resource) {
    this.#resourcesTemplates.push(resource);
  }
  addPrompt(prompt) {
    this.#prompts.push(prompt);
  }
  async start(options = {
    transportType: "stdio"
  }) {
    if (options.transportType === "stdio") {
      const transport = new StdioServerTransport;
      const session = new FastMCPSession({
        name: this.#options.name,
        version: this.#options.version,
        tools: this.#tools,
        resources: this.#resources,
        resourcesTemplates: this.#resourcesTemplates,
        prompts: this.#prompts
      });
      await session.connect(transport);
      this.#sessions.push(session);
      this.emit("connect", {
        session
      });
    } else if (options.transportType === "sse") {
      this.#sseServer = await startSSEServer({
        endpoint: options.sse.endpoint,
        port: options.sse.port,
        createServer: async (request) => {
          let auth;
          if (this.#authenticate) {
            auth = await this.#authenticate(request);
          }
          return new FastMCPSession({
            auth,
            name: this.#options.name,
            version: this.#options.version,
            tools: this.#tools,
            resources: this.#resources,
            resourcesTemplates: this.#resourcesTemplates,
            prompts: this.#prompts
          });
        },
        onClose: (session) => {
          this.emit("disconnect", {
            session
          });
        },
        onConnect: async (session) => {
          this.#sessions.push(session);
          this.emit("connect", {
            session
          });
        }
      });
      console.info(`server is running on SSE at http://localhost:${options.sse.port}${options.sse.endpoint}`);
    } else {
      throw new Error("Invalid transport type");
    }
  }
  async stop() {
    if (this.#sseServer) {
      this.#sseServer.close();
    }
  }
};

// index.ts
var server = new FastMCP({
  name: "Linear MCP Server",
  version: "0.0.1"
});
var linear = new import_sdk.LinearClient({
  apiKey: process.env.LINEAR_API_KEY
});
server.addTool({
  name: "linear-search-issues",
  description: "Search for issues in Linear",
  parameters: z.object({
    query: z.string().describe("Search term"),
    teamId: z.string().optional().describe("Filter by team ID"),
    status: z.string().optional().describe("Filter by status name (e.g., 'In Progress', 'Done')"),
    assigneeId: z.string().optional().describe("Filter by assignee's user ID"),
    labels: z.array(z.string()).optional().describe("Filter by label names"),
    project: z.string().optional().describe("Filter by project name"),
    priority: z.number().optional().describe("Filter by priority (1=urgent, 2=high, 3=normal, 4=low)"),
    estimate: z.number().optional().describe("Filter by estimate points"),
    includeArchived: z.boolean().optional().describe("Include archived issues in results (default: false)"),
    limit: z.number().optional().describe("Max results to return (default: 10)").default(10)
  }),
  execute: async (args) => {
    try {
      const filter = {};
      if (args.query) {
        filter.or = [
          { title: { contains: args.query } },
          { description: { contains: args.query } }
        ];
      }
      if (args.teamId) {
        filter.team = { id: { eq: args.teamId } };
      }
      if (args.status) {
        filter.state = { name: { eq: args.status } };
      }
      if (args.assigneeId) {
        filter.assignee = { id: { eq: args.assigneeId } };
      }
      if (args.labels && args.labels.length > 0) {
        filter.labels = {
          some: {
            name: { in: args.labels }
          }
        };
      }
      if (args.project) {
        filter.project = { name: { eq: args.project } };
      }
      if (args.priority) {
        filter.priority = { eq: args.priority };
      }
      if (args.estimate) {
        filter.estimate = { eq: args.estimate };
      }
      const res = await linear.searchIssues(args.query, {
        filter,
        first: args.limit,
        includeArchived: args.includeArchived || false
      });
      const issues = await Promise.all(res.nodes.map(async (node) => {
        let status = null;
        if (node.state) {
          status = await node.state;
        }
        let assignee = null;
        if (node.assignee) {
          assignee = await node.assignee;
        }
        let project = null;
        if (node.project) {
          project = await node.project;
        }
        return {
          id: node.id,
          identifier: node.identifier,
          title: node.title,
          description: node.description,
          priority: node.priority,
          estimate: node.estimate,
          status,
          assignee,
          project,
          url: node.url
        };
      }));
      return { content: issues.map((issue) => ({ type: "text", text: JSON.stringify(issue) })) };
    } catch (error) {
      return { content: [{ type: "text", text: `Error: ${error}` }] };
    }
  }
});
server.start({
  transportType: "stdio"
});
